        },
        {
          "inlineData": {
            "mimeType": "application/pdf",
            "data": $('Webhook - Upload PDF').item.json.body.pdf_base64
          }
        }
      ]
    }
  ],
  "generationConfig": {
    "responseMimeType": "application/json"
  }
}) }}

parameters.jsCode:
// Parse Gemini response
const response = $input.item.json;
let content;
try {
  content = response.candidates[0].content.parts[0].text;
} catch (e) {
  return { json: { error: 'Failed to read Gemini response', raw: JSON.stringify(response).substring(0, 500) } };
}

let extracted;
try {
  let jsonStr = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  extracted = JSON.parse(jsonStr);
} catch (e) {
  return { json: { error: 'Failed to parse JSON', raw: content } };
}

// Seasonal booking link
const currentMonth = new Date().getMonth() + 1;
let bookingLink, consultationType;
if (currentMonth >= 3 && currentMonth <= 8) {
  bookingLink = 'https://calendly.com/swans-santiago-p/summer-spring';
  consultationType = 'in-office consultation';
} else {
  bookingLink = 'https://calendly.com/swans-santiago-p/winter-autumn';
  consultationType = 'virtual consultation';
}

// Accident summary
const accidentSummary = extracted.num_injured > 0
  ? 'Based on the police report, injuries were sustained in the accident. Your health and well-being are our top priority, and we want to ensure you receive proper compensation for any medical expenses and pain and suffering.'
  : 'Fortunately, no injuries were reported in the accident. However, you may still be entitled to compensation for property damage and other related expenses.';

// SOL date (3 years from accident)
let solDate = '';
if (extracted.accident_date) {
  const d = new Date(extracted.accident_date);
  if (!isNaN(d.getTime())) {
    d.setFullYear(d.getFullYear() + 3);
    solDate = d.toISOString().split('T')[0];
  }
}

// Resolve nested accident_location
const accidentLocation = (typeof extracted.accident_location === 'object' && extracted.accident_location !== null)
  ? (extracted.accident_location.full_location || JSON.stringify(extracted.accident_location))
  : (extracted.accident_location || '');

// Plate number
const clientPlate = (extracted.vehicle1 && extracted.vehicle1.plate_number)
  ? extracted.vehicle1.plate_number
  : (extracted.client_plate || '');

// Client name
const clientFirstName = extracted.client_first_name || '';
const clientLastName = extracted.client_last_name || '';

// Defendant name
const defendantName = extracted.defendant_name || '';

return {
  json: {
    client_first_name: clientFirstName,
    client_last_name: clientLastName,
    client_full_name: (clientFirstName + ' ' + clientLastName).trim(),
    defendant_name: defendantName,
    accident_date: extracted.accident_date || '',
    accident_date_formatted: extracted.accident_date || '',
    accident_location: accidentLocation,
    client_plate: clientPlate,
    client_pronoun: extracted.client_pronoun || 'they',
    sol_date: solDate,
    has_injuries: (extracted.num_injured || 0) > 0,
    num_injured: extracted.num_injured || 0,
    booking_link: bookingLink,
    consultation_type: consultationType,
    accident_summary: accidentSummary,
    accident_description: extracted.accident_description || '',
    _raw_extraction: extracted
  }
};

// Prepare email data
const body = $('Webhook - Validated Data').item.json.body;
const clioDocUrl = $json.clio_document_url || '';

const currentMonth = new Date().getMonth() + 1;
let bookingLink, consultationType;
if (currentMonth >= 3 && currentMonth <= 8) {
  bookingLink = 'https://calendly.com/swans-santiago-p/summer-spring';
  consultationType = 'in-office consultation';
} else {
  bookingLink = 'https://calendly.com/swans-santiago-p/winter-autumn';
  consultationType = 'virtual consultation';
}

let injurySummary;
if (body.num_injured > 0) {
  injurySummary = 'Based on the police report, injuries were sustained in the accident. Your health and well-being are our top priority, and we want to ensure you receive proper compensation for any medical expenses and pain and suffering.';
} else {
  injurySummary = 'Fortunately, no injuries were reported in the accident. However, you may still be entitled to compensation for property damage and other related expenses.';
}

return {
  json: {
    to_email: body.client_email || 'REDACTED@email.com',
    subject: 'Retainer Agreement for Your Review – Richards & Law',
    client_first_name: body.client_first_name,
    client_full_name: body.client_full_name,
    defendant_name: body.defendant_name,
    accident_date_formatted: body.accident_date_formatted || body.accident_date,
    accident_location: body.accident_location,
    injury_summary: injurySummary,
    booking_link: bookingLink,
    consultation_type: consultationType,
    clio_document_url: clioDocUrl
  }
};

